SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_fin_cheque_tobank ON sc_fin_cheque_tobank CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_fin_cheque_tobank() RETURNS trigger AS $BODY$
BEGIN

  if coalesce(NEW.tobank_status::text, '') = '' or NEW.tobank_status <> '1' then NEW.tobank_status  := '0';end if;
  if coalesce(NEW.cheque_amount::text, '') = '' then NEW.cheque_amount := 0;end if;
  if coalesce(NEW.cancel_status::text, '') = '' or NEW.cancel_status <>'1' then NEW.cancel_status := '0';end if;

  if (coalesce(OLD.vourcher_no::text, '') = '' and (NEW.vourcher_no IS NOT NULL AND NEW.vourcher_no::text <> '')) then
    if (pka.auto_entry) then 
      NEW.entry_id := current_setting('app.login_id', true);
      NEW.entry_date := statement_timestamp();
      NEW.entry_branch := current_setting('app.login_br', true);
    end if;
  end if;

  --Auto item_no
  if (pka.auto_seqno) then
    if coalesce(NEW.item_no::text, '') = '' or NEW.item_no = 0 then
      select max(item_no) into STRICT NEW.item_no
      from sc_fin_cheque_tobank
      where (vourcher_no = NEW.vourcher_no);
      if NEW.item_no > 0 then
        NEW.item_no := NEW.item_no + 1;
      else
        NEW.item_no := 1;
      end if;
    end if;
  end if;

  if coalesce(trim(both NEW.clearing_status)::text, '') = '' then NEW.clearing_status := 2;end if;

  if OLD.clearing_status = '2' and ( NEW.clearing_status = '1' or NEW.clearing_status = '0' ) then
    -- ทำรายการผ่านเช็ค / ไม่ผ่าน
    NEW.clearing_id := pka_com_function.fp_login_id;
    NEW.clearing_br := pka_com_function.fp_login_br;
    NEW.clearing_pc := pka_com_function.fp_login_pc;
    NEW.clearing_findate := pka_fin_daily.fp_finance_date('1');  -- วันที่การเงินที่ทำ
    NEW.clearing_time := statement_timestamp();
  end if;



RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_fin_cheque_tobank() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_fin_cheque_tobank
	BEFORE INSERT OR UPDATE ON sc_fin_cheque_tobank FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_fin_cheque_tobank();

